import anthropic

client = anthropic.Anthropic()

def generate_with_uncertainty_check(question: str) -> dict:
    """Generate a response and ask the model to flag uncertain claims."""
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        system=(
            "You are a factual assistant. After answering, list any claims you "
            "are less than highly confident about under a 'UNCERTAIN CLAIMS:' heading. "
            "If you do not know the answer, say so explicitly rather than guessing. "
            "Never fabricate names, dates, citations, or statistics."
        ),
        messages=[{"role": "user", "content": question}],
    )
    raw = response.content[0].text
    if "UNCERTAIN CLAIMS:" in raw:
        answer, uncertain_section = raw.split("UNCERTAIN CLAIMS:", 1)
        uncertain_claims = [
            c.strip("- ").strip()
            for c in uncertain_section.strip().splitlines()
            if c.strip()
        ]
    else:
        answer = raw
        uncertain_claims = []
    return {"answer": answer.strip(), "uncertain_claims": uncertain_claims}

# Usage
result = generate_with_uncertainty_check(
    "What was the GDP of Estonia in 2019 and who was the Prime Minister at the time?"
)
print(result["answer"])
if result["uncertain_claims"]:
    print("\nUncertain claims requiring verification:")
    for claim in result["uncertain_claims"]:
        print(f"  - {claim}")
